221	 */
222	export const publicProcedure = t.procedure.use(observabilityMiddleware);
223	
224	/**
225	 * User-Scoped Procedure
226	 *
227	 * For user-level operations: account settings, profile, list orgs, create org.
228	 * Accepts both clerk-pending (no org) and clerk-active (has org) users.
229	 *
