241	  .use(observabilityMiddleware)
242	  .use(({ ctx, next }) => {
243	    if (ctx.auth.type === "unauthenticated") {
244	      throw new TRPCError({
245	        code: "UNAUTHORIZED",
246	        message: "Authentication required. Please sign in.",
247	      });
248	    }
249	
250	    // Allow both clerk-pending and clerk-active
251	    if (ctx.auth.type !== "clerk-pending" && ctx.auth.type !== "clerk-active") {
252	      throw new TRPCError({
253	        code: "UNAUTHORIZED",
254	        message: "Clerk authentication required",
255	      });
256	    }
257	
258	    return next({
259	      ctx: {
260	        ...ctx,
261	        // Type-safe: either clerk-pending or clerk-active
262	        auth: ctx.auth as Extract<
263	          AuthContext,
264	          { type: "clerk-pending" | "clerk-active" }
265	        >,
266	      },
267	    });
268	  });
